function getByEncode(_) {
    let { scale, field, accessor, value } = _;

    if (!accessor) {
        if (field) {
            accessor = d => d[field.dataindex];
        } else {
            accessor = d => d;
        }
    }

    if (!value) {
        value = function(_) {
            let { scale, field, config } = _;
            return function(d, i) {
                return scale(accessor(d));
            };
        };
    }

    return value(_);
}

export { getByEncode };

